import React, { createContext, useState, useContext, useEffect } from 'react';
import { authAPI } from '../utils/api';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');
    const storedSalary = localStorage.getItem('salary');
    if (token && userData) {
      const parsedUser = JSON.parse(userData);
      setUser({ ...parsedUser, salary: storedSalary ? parseFloat(storedSalary) : parsedUser.salary });
    }
    setLoading(false);
  }, []);

  const logout = () => {
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    localStorage.removeItem('salary');
  };

  // New: Set or update monthly salary
  const setSalary = (amount) => {
    setUser(prev => ({ ...prev, salary: amount }));
    localStorage.setItem('salary', amount);
  };

  const value = {
    user,
    logout,
    setSalary,   // make salary editable
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

export { AuthContext };
